/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Pedido Venda"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedNovStsCod.IsEmpty()
print printBlockFilterPedNovStsCod EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedCliRaz.IsEmpty() print printBlockFilterPedCliRaz EndIf If not &PedStsFin.IsEmpty() &FilterPedStsFinValueDescription = &PedStsFin.EnumerationDescription()
print printBlockFilterPedStsFin EndIf If not &PedNovStsFinCod.IsEmpty()
print printBlockFilterPedNovStsFinCod EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emi.", "à") print printBlockFilterPedDtaEms_To EndIf If not &PedDtaPrv.IsEmpty() print printBlockFilterPedDtaPrv EndIf If not &PedDtaPrv_To.IsEmpty() &PedDtaPrv_To_Description = format('%1 (%2)', "Ent.", "à") print printBlockFilterPedDtaPrv_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PEDDTARETCON' &PedDtaRetCon1.FromString(&GridStateDynamicFilter.Value) &PedDtaRetCon_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaRetCon1.IsEmpty() &FilterPedDtaRetConDescription = "Retorno" &PedDtaRetCon = &PedDtaRetCon1 print printBlockFilterPedDtaRetCon EndIf If not &PedDtaRetCon_To1.IsEmpty() &FilterPedDtaRetConDescription = format('%1 (%2)', "Retorno", "à") &PedDtaRetCon = &PedDtaRetCon_To1 print printBlockFilterPedDtaRetCon EndIf Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PEDDTARETCON' &PedDtaRetCon2.FromString(&GridStateDynamicFilter.Value) &PedDtaRetCon_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaRetCon2.IsEmpty() &FilterPedDtaRetConDescription = "Retorno" &PedDtaRetCon = &PedDtaRetCon2 print printBlockFilterPedDtaRetCon EndIf If not &PedDtaRetCon_To2.IsEmpty() &FilterPedDtaRetConDescription = format('%1 (%2)', "Retorno", "à") &PedDtaRetCon = &PedDtaRetCon_To2 print printBlockFilterPedDtaRetCon EndIf Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PEDDTARETCON' &PedDtaRetCon3.FromString(&GridStateDynamicFilter.Value) &PedDtaRetCon_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaRetCon3.IsEmpty() &FilterPedDtaRetConDescription = "Retorno" &PedDtaRetCon = &PedDtaRetCon3 print printBlockFilterPedDtaRetCon EndIf If not &PedDtaRetCon_To3.IsEmpty() &FilterPedDtaRetConDescription = format('%1 (%2)', "Retorno", "à") &PedDtaRetCon = &PedDtaRetCon_To3 print printBlockFilterPedDtaRetCon EndIf Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order EmpCod FilCod PedCliRaz PedNovCliRaz when &OrderedBy = 3 order PedCod when &OrderedBy = 4 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 4 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 5 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 5 AND &OrderedDsc = True order PedHorEms when &OrderedBy = 6 AND &OrderedDsc = False order (PedHorEms) when &OrderedBy = 6 AND &OrderedDsc = True order PedDtaPrv when &OrderedBy = 7 AND &OrderedDsc = False order (PedDtaPrv) when &OrderedBy = 7 AND &OrderedDsc = True order PedDtaRetCon when &OrderedBy = 8 AND &OrderedDsc = False order (PedDtaRetCon) when &OrderedBy = 8 AND &OrderedDsc = True order PedDtaFat when &OrderedBy = 9 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 9 AND &OrderedDsc = True order PedVlrBrt when &OrderedBy = 10 AND &OrderedDsc = False order (PedVlrBrt) when &OrderedBy = 10 AND &OrderedDsc = True order PedVlrLiq when &OrderedBy = 11 AND &OrderedDsc = False order (PedVlrLiq) when &OrderedBy = 11 AND &OrderedDsc = True order LctCod when &OrderedBy = 12 AND &OrderedDsc = False order (LctCod) when &OrderedBy = 12 AND &OrderedDsc = True order PedVenCod when &OrderedBy = 13 AND &OrderedDsc = False order (PedVenCod) when &OrderedBy = 13 AND &OrderedDsc = True
using DSwwLocacaoProdutos(&PedCod, &PedSts, &PedNovStsCod, &PedCliCod, &PedCliRaz, &PedStsFin , &PedNovStsFinCod, &PedDtaEms, &PedDtaEms_To, &PedDtaPrv, &PedDtaPrv_To, &LctTip , &LctAtuSal, &PedBlq, &FilCod, &DynamicFiltersSelector1, &PedDtaRetCon1, &PedDtaRetCon_To1 , &LctCod1, &PedVenCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PedDtaRetCon2, &PedDtaRetCon_To2 , &LctCod2, &PedVenCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PedDtaRetCon3, &PedDtaRetCon_To3 , &LctCod3, &PedVenCod3)
if PedCliCodRaz_Nov.Length() > 30 &PedCliCodRaz_Nov = substr(PedCliCodRaz_Nov, 1, 30) + '...' Else &PedCliCodRaz_Nov = PedCliCodRaz_Nov EndIf
If PedStsFinIsPar = true &AuxFin = 'PAR.' Else &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3)) Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwLocacaoProdutosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwLocacaoProdutosGridState")) Else &GridState.FromXml(&Session.Get(!"wwLocacaoProdutosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSCOD" &PedNovStsCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLIRAZ" &PedCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINCOD" &PedNovStsFinCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"PEDDTAPRV" &PedDtaPrv.FromString(&GridStateFilterValue.Value) &PedDtaPrv_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
